/* ── Workspace persistence (platform per-user storage) ────────────────── */
const STORE_KEY = "inkwell-state-v1";
const PROFILE_KEY = "inkwell-profile-v1";
/* ── Environment ──────────────────────────────────────────────────────────
   Detected BEFORE the storage shim below runs, because the shim itself defines
   window.storage and would otherwise make every environment look like the
   sandbox. */
const IN_CLAUDE_SANDBOX = typeof window !== "undefined" && !!window.storage;

/* Where the AI calls go.

   Inside the Claude artifact sandbox the host intercepts requests to the
   Anthropic API and injects the key, so the browser can call it directly.
   Nowhere else can: that request is CORS-blocked and carries no key, so a
   deployed build MUST go through a server-side proxy that holds the key.
   `api/claude.js` in this project is that proxy.

   Override at runtime if your route differs, before the app mounts:
     window.__AI_ENDPOINT__ = "/api/my-route"; */

/* ── Storage adapter ──────────────────────────────────────────────────────
   Everything here persists through `window.storage`, which is injected by the
   Claude artifact sandbox. Anywhere else — a Vercel deploy, a plain browser, a
   file:// open — that object does not exist. hasStore() then returned false,
   boot fell straight through to "guest", and the welcome + sign-up screen was
   skipped entirely. That is why the login card "vanished" once the app left the
   sandbox, and why nothing could autosave off-platform.

   This shim provides the same async key/value contract on top of localStorage
   whenever the sandbox API is absent, so the app boots and saves anywhere.
   The sandbox's own storage still wins when it is present. */
if (typeof window !== "undefined" && !window.storage) {
  const PFX = "shortlist:";
  const ok = (() => {
    try { const t = "__t"; localStorage.setItem(t, "1"); localStorage.removeItem(t); return true; }
    catch (e) { return false; }   /* private mode / storage disabled */
  })();
  if (ok) {
    window.storage = {
      async get(key) {
        const v = localStorage.getItem(PFX + key);
        return v === null ? null : { key, value: v, shared: false };
      },
      async set(key, value) {
        localStorage.setItem(PFX + key, String(value));
        return { key, value: String(value), shared: false };
      },
      async delete(key) {
        localStorage.removeItem(PFX + key);
        return { key, deleted: true, shared: false };
      },
      async list(prefix = "") {
        const keys = [];
        for (let i = 0; i < localStorage.length; i++) {
          const k = localStorage.key(i);
          if (k && k.startsWith(PFX + prefix)) keys.push(k.slice(PFX.length));
        }
        return { keys, prefix, shared: false };
      },
    };
  }
}

const hasStore = () => typeof window !== "undefined" && window.storage && typeof window.storage.get === "function";
const storeGet = async k => {
  try { const r = await window.storage.get(k); return r && r.value ? JSON.parse(r.value) : null; }
  catch (e) { return null; }
};
const storeSetRaw = async (k, str) => {
  try { const r = await window.storage.set(k, str); return !!r; }
  catch (e) { return false; }
};
const storeSet = (k, obj) => storeSetRaw(k, JSON.stringify(obj));
const storeDel = async k => { try { await window.storage.delete(k); } catch (e) {} };

