/* Staged import loader: a glowing gradient ring plus a live checklist of
   what's happening, timed to feel truthful (steps advance, the last one
   holds until the work actually finishes). */
const ImportStages = ({ styleToo }) => {
  const steps = ["Reading your file", "Extracting the text", "Understanding the sections", "Drafting your fields", styleToo ? "Matching your layout" : "Final touches"];
  const [ix, setIx] = React.useState(0);
  React.useEffect(() => {
    const t = setInterval(() => setIx(i => Math.min(i + 1, steps.length - 1)), 2100);
    return () => clearInterval(t);
  }, []);
  return (
    <div style={{ display:"flex", alignItems:"center", gap:18, textAlign:"left", padding:"4px 2px" }}>
      <span className="impRing" aria-hidden="true"><span /></span>
      <div style={{ flex:1, minWidth:0 }}>
        {steps.map((s, i) => (
          <div key={s} className={"impStep" + (i < ix ? " done" : i === ix ? " now" : "")}>
            <span className="tick">{i < ix ? "✓" : i === ix ? "" : "·"}</span>
            <span>{s}{i === ix ? "…" : ""}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

const FileIcon = ({ kind = "pdf", size = 18 }) => {
  const h = Math.round(size * 48 / 40);
  const html = (ICON_SVG[kind] || ICON_SVG.pdf).replace("<svg ", `<svg width="${size}" height="${h}" `);
  return <span aria-hidden="true" style={{ display:"inline-flex", width:size, height:h, flex:"none", lineHeight:0 }} dangerouslySetInnerHTML={{ __html: html }} />;
};

/* ── Resolve the current page-margin preset (all four sides equal) ── */
const marginPreset = d => {
  const near = (a, b) => Math.abs(a - b) < 0.02;
  const s = [d.mT, d.mR, d.mB, d.mL];
  const all = v => s.every(x => near(x, v));
  if (all(0.7)) return "0.7";
  if (all(1)) return "1";
  if (all(1.35)) return "1.35";
  return "0";
};

/* ── Stable, smooth Slider. Defined at MODULE scope (not inside the app
   component) so React never unmounts/remounts it on each keystroke — that
   remounting was what made every slider jump only one step per drag. ── */
const _RS_MUTE = "#8A847D", _RS_HAIR = "#DDD8D2", _RS_INK = "#1B1A19";
const _sldFld = { marginBottom:13 };
const _sldLbl = { display:"block", fontSize:9.5, color:_RS_MUTE, marginBottom:5, fontWeight:600, textTransform:"uppercase", letterSpacing:1.1 };
const Slider = ({ label, value, min, max, step = 1, onChange, fmt = v => v + "%" }) => {
  const unit = String(fmt(0)).replace(/[\d.\s-]/g, "") || "";
  const clamp = n => Math.max(min, Math.min(max, n));
  const pct = ((value - min) / (max - min)) * 100;
  return (
    <div style={_sldFld}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
        <span style={_sldLbl}>{label}</span>
        <span style={{ display:"inline-flex", alignItems:"center", gap:3, border:`1px solid ${_RS_HAIR}`, borderRadius:6, padding:"1px 5px", background:"#fff" }}>
          <input type="number" min={min} max={max} step={step} value={value}
            onChange={e => { const n = Number(e.target.value); if (!Number.isNaN(n)) onChange(clamp(n)); }}
            style={{ width:38, border:"none", outline:"none", background:"transparent", color:_RS_INK, fontSize:11, fontWeight:600, textAlign:"right", MozAppearance:"textfield" }} />
          {unit && <span style={{ fontSize:10, color:_RS_MUTE }}>{unit}</span>}
        </span>
      </div>
      <input className="rsrange" type="range" min={min} max={max} step={step} value={value}
        onChange={e => onChange(Number(e.target.value))} style={{ width:"100%", "--pct": pct + "%" }} />
    </div>
  );
};

