/* ── Help centre FAQ. Kept at module scope so the copy sits in one place.
   `g` groups a row: "basics" for the common questions, "deep" for the
   features people only find by accident. ── */
const FAQS = [
  { g:"basics", q: "Where does my CV actually live?",
    a: "In your own browser storage on this device, not on a server. Nothing is uploaded to be stored, and clearing your browser data clears your CV with it, so export a PDF once you are happy." },
  { g:"basics", q: "Will an ATS be able to read this?",
    a: "Open Polish & Checks and turn on the ATS x-ray: it shows your CV the way a parser sees it, as flat text in reading order. If a two-column template scrambles that order, the x-ray makes it obvious before a recruiter's system does." },
  { g:"basics", q: "Does importing my old CV keep how it looked?",
    a: "Yes. Smart Import reads the layout as well as the words — tables or plain bullets, serif or sans, your accent colour, heading bars, bullet character, spacing — and starts you on the closest template. Every part of it stays editable afterwards." },
  { g:"basics", q: "I picked an accent colour and nothing changed.",
    a: "Monochrome mode was almost certainly on, at the bottom of the Colours group in Design Studio. It forces the whole CV to ink for printing, which overrides any accent. Picking a colour now switches Monochrome off for you automatically." },
  { g:"basics", q: "Can I keep different CVs for different applications?",
    a: "That is what Versions are for. Duplicate a version, tailor it against a pasted job description, and each one keeps its own content, design, and layout. Compare any two of them line by line." },
  { g:"basics", q: "Something broke, or I changed my mind.",
    a: "Ctrl / ⌘ Z undoes anything, including AI edits and imports. If it is a genuine bug, mail it to ali.shortlist@gmail.com and it gets read." },

  { g:"deep", q: "How do I control margins, columns, and row heights exactly?",
    a: "Two ways, and they drive the same values. Drag the purple handles directly on the page the way you would in Canva, or type exact numbers in Design Studio if you need a spec met. Margins, column widths, and row spacing each have handles; hold and drag, and the page reflows live." },
  { g:"deep", q: "Can I format one word instead of the whole line?",
    a: "Yes. Select the text first, then use the size and font controls — they apply to the selection, not the block, exactly like Word or Canva. With nothing selected they fall back to the whole field, which is what you usually want." },
  { g:"deep", q: "What does the space lens actually measure?",
    a: "It shades each section by how much vertical space it eats relative to how much you have to say. A section glowing hot with three lines of content is a section that is costing you a page for nothing — usually padding, a heading bar, or an entry divider you forgot you turned on." },
  { g:"deep", q: "How does tailoring against a job description work?",
    a: "Paste the posting into Tailor for Job. It reads the required skills out of the text, checks them against what your CV already evidences, and marks the gaps. It will not invent experience you do not have — it points at the bullets worth rewording and leaves the judgement to you." },
  { g:"deep", q: "Can someone review my CV without editing it?",
    a: "Versions → Create feedback copy exports a standalone HTML file. A mentor opens it anywhere, clicks any line to comment, and sends the file back — their notes land in your Feedback list, attached to the exact lines they were about." },
  { g:"deep", q: "What is Interview mode for?",
    a: "It turns the finished CV into a teleprompter of talking points, one entry at a time, so you rehearse against the same document the interviewer is reading. It never changes the CV itself." },
  { g:"deep", q: "My two-column template pushes a section onto page two.",
    a: "Open Arrange Sections and move the offender into the shorter column, or turn on Fit to shrink spacing before you touch font size. Shrinking type is the last resort — the ATS x-ray will show you if a column swap broke reading order." },
  { g:"deep", q: "Can I get my data out, or move to another machine?",
    a: "Versions → Download backup writes every version, design, and layout to a single JSON file. Restore it on any device and everything comes back exactly as it was, including your feedback notes." },
];

