/* ═══ v12 helpers: anonymise, dates, type scales, font pairs, lint, x-ray ═══ */

/* Blind-screening view of the data. Applied at render time only, so the
   underlying version is untouched and the toggle is instantly reversible. */
const ANON_DATA = d => ({
  ...d,
  personal: { ...d.personal, name:"Candidate", email:"", phone:"", linkedin:"", location:"", rollNumber:"", photo:"" },
  education: (d.education || []).map(e => ({ ...e, score:"" })),
});

/* — date normaliser — */
const MONTH_NUM = { jan:1, feb:2, mar:3, apr:4, may:5, jun:6, jul:7, aug:8, sep:9, oct:10, nov:11, dec:12 };
const MONTH_NAME = ["", "Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
const fmtDatePart = (mo, yr, fmt) => {
  if (fmt === "yyyy" || !mo) return String(yr);
  if (fmt === "mm-yyyy") return String(mo).padStart(2, "0") + "/" + yr;
  return MONTH_NAME[mo] + " " + yr;
};
const normalizeDateStr = (s, fmt) => {
  if (typeof s !== "string" || !s.trim()) return s;
  let out = s;
  if (fmt !== "keep") {
  /* month name + year: "March 2024", "Mar'24", "Sept. 24" */
  out = out.replace(/\b(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*\.?\s*'?\s*(\d{4}|\d{2})\b/gi, (m, mon, yr) => {
    const mo = MONTH_NUM[mon.toLowerCase()];
    let y = +yr; if (String(yr).length === 2) y += y > 60 ? 1900 : 2000;
    return fmtDatePart(mo, y, fmt);
  });
  /* numeric mm/yyyy or mm-yyyy */
  out = out.replace(/\b(0?[1-9]|1[0-2])[\/.](\d{4})\b/g, (m, mo, yr) => fmtDatePart(+mo, +yr, fmt));
  }
  /* range separators: hyphen or "to" between dates becomes an en dash */
  out = out.replace(/(\d)\s*(?:--|—|-|\bto\b|\btill\b|\buntil\b)\s*(?=\d|[A-Z]|present|current|now|ongoing|date)/gi, "$1 \u2013 ");
  out = out.replace(/\b(present|current|ongoing)\b/gi, m => m[0].toUpperCase() + m.slice(1).toLowerCase());
  return out.replace(/[ \t]{2,}/g, " ").trim();
};
/* every field on the CV that holds a date, rewritten to one format */
const normalizeAllDates = (d, fmt) => ({
  ...d,
  education: d.education.map(e => ({ ...e, year: normalizeDateStr(e.year, fmt) })),
  achievements: d.achievements.map(g => ({ ...g, items: g.items.map(i => ({ ...i, year: normalizeDateStr(i.year, fmt) })) })),
  experience: d.experience.map(e => ({ ...e, duration: normalizeDateStr(e.duration, fmt) })),
  positions: d.positions.map(p => ({ ...p, year: normalizeDateStr(p.year, fmt) })),
  extraCurricular: d.extraCurricular.map(g => ({ ...g, items: g.items.map(i => ({ ...i, year: normalizeDateStr(i.year, fmt) })) })),
  competitions: d.competitions.map(c => ({ ...c, year: normalizeDateStr(c.year, fmt) })),
});

