    const el = document.activeElement;
    if (!el || (el.tagName !== "INPUT" && el.tagName !== "TEXTAREA")) return false;
    const s0 = el.selectionStart, e0 = el.selectionEnd;
    if (s0 == null || e0 == null || s0 === e0) return false;
