      const body = serializeMarks(lt);
      const loc = id && !id.startsWith("spike:") ? findLoc(id) : null;
      const cur0 = loc ? String((loc.b || loc.c || loc.e || {})[fld] || "") : "";
      const had = cur0.match(/^\[\[[lcrj]\]\]/);
      const next = (had && had[0] === token) || (token === "[[l]]" && !force) ? body : token + body;
